#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        long long count = 0;
        for (int a = 1; a <= N; a++) {
            int b = M - (a % M);
            if (b > a && b <= N) {
                count++;
            }
        }
        printf("%lld\n", count);
    }
    return 0;
}

