    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int M = sc.nextInt();
            long count = 0;
            for (int a = 1; a <= N; a++) {
                int b = M - (a % M);
                if (b > a && b <= N) {
                    count++;
                }
            }
            System.out.println(count);
        }
    }
}

